using System;
using Avalonia.Animation;
using Avalonia.Controls;
using LuminaUI.Controls;

LuminaShell? shell = LuminaShell.FindFor(this);
// 也可以操作指定 Shell：
// LuminaShell? shell = LuminaShell.GetShell("App");

if (shell == null)
{
    return;
}

Control CreateDetailsContent()
{
    return new DetailsView();
}

// 使用 Shell 默认切页动画。
await shell.PushAsync(CreateDetailsContent());

// 只覆盖本次 Push 的动画。
await shell.PushAsync(
    CreateDetailsContent(),
    new PageSlide(TimeSpan.FromMilliseconds(240), PageSlide.SlideAxis.Horizontal));

// 本次 Push 不播放动画。
await shell.PushAsync(
    CreateDetailsContent(),
    LuminaShellPushOptions.WithoutPageTransition());

// 保留 Header，但隐藏菜单和汉堡按钮。
await shell.PushAsync(
    CreateDetailsContent(),
    new LuminaShellPushOptions
    {
        ShowShellMenu = false
    });

// 隐藏 Header，但保留菜单布局。
await shell.PushAsync(
    CreateDetailsContent(),
    new LuminaShellPushOptions
    {
        ShowShellHeader = false
    });

// 完全覆盖 Shell：无 Header、无菜单，内容从顶部开始。
await shell.PushAsync(
    CreateDetailsContent(),
    LuminaShellPushOptions.FullScreen());

// 同时指定动画和覆盖策略。
await shell.PushAsync(
    CreateDetailsContent(),
    new LuminaShellPushOptions
    {
        PageTransition = new CrossFade(TimeSpan.FromMilliseconds(180)),
        ShowShellHeader = false,
        ShowShellMenu = false
    });
